          roundsA >= 3 ? maxPriority + 1 : taskA.priority;
        const priorityB =
          roundsB >= 3 ? maxPriority + 1 : taskB.priority;

        if (priorityA !== priorityB) {
          return priorityB - priorityA;
        }
        return a.localeCompare(b);
      });

